  const T_jis=T_lim/sf;           // JIS標準値（ボルト強度基準）
  const softMaterials=new Set(['aluminum','cast_iron','brass','resin']);
  const isSoft=softMaterials.has(partMatKey);
  const T_rec=isSoft?Math.min(T_jis,T_fail/sf):T_jis;
  const isMaterialLimit=isSoft&&T_fail/sf<T_jis;

